class Solution {
public:
    vector<int> maxDepthAfterSplit(string seq) {
        int openA = 0, openB = 0;
        vector<int> res(seq.size());
        for (int i = 0; i < seq.size(); ++i) {
            if (seq[i] == '(') {
                if (openA <= openB) {
                    openA++;
                    res[i] = 0;
                } else {
                    openB++;
                    res[i] = 1;
                }
            } else {
                if (openA > openB) {
                    openA--;
                    res[i] = 0;
                } else {
                    openB--;
                    res[i] = 1;
                }
            }
        }
        return res;
    }
};
